head.script:
// 테스트 설명, 유효성 값 설정 (Jira WAEA-939)
scwin.tData = {
    "description" : "[우리카드] inputCalendar dateValidCheck 시 붙여넣기 이상 동작<br/><a href='https://inswave01.atlassian.net/browse/WAEA-939' target='_blank' style='color:blue;text-decoration:underline;'>WAEA-939</a>",
    "validation" : [
        "dateValidCheck(유효성 검증) 속성을 적용한 inputCalendar 에서 무효한 날짜를 입력해 유효성 메시지가 표시된 직후 유효한 날짜(2026-06-24)를 붙여넣으면, 일(日) 자리가 누락되지 않고 입력한 전체 날짜가 그대로 입력되어야 한다.",
        "유효성 메시지가 표시되지 않은 정상 상태(초기 상태 또는 유효 날짜 입력 후)에서 유효한 날짜를 붙여넣으면 전체 값이 올바르게 입력되어, 에러 상태 경로 수정이 일반 붙여넣기 경로를 깨뜨리지 않아야 한다.",
        "표시형식(yyyy-MM-dd) 길이를 초과하는 문자열을 붙여넣어도 입력형식에 맞는 길이로 절단/포맷 처리가 유지되어, 수정으로 maxlength/포맷 처리가 무력화되지 않아야 한다.",
        "calendarValueType 이 시/분을 포함하는 형식(yearMonthDateTime)인 inputCalendar 에서 붙여넣으면 입력형식이 표시형식(yyyy-MM-dd HH:mm)으로 올바르게 변환되어, 다른 입력형식의 붙여넣기 변환이 함께 깨지지 않아야 한다.",
        "유효성 메시지 표시 이후 키보드로 직접 타이핑하여 유효한 날짜를 입력하면 전체 값이 정상 입력되어, 붙여넣기 경로 수정이 직접 타이핑 입력 경로를 깨뜨리지 않아야 한다.",
        "무효한 날짜를 붙여넣으면 dateValidCheck 유효성 검증과 메시지가 정상 발동하고, 부분/빈 값을 붙여넣은 뒤 포커스 아웃하면 잔존 부분 값 없이 빈값으로 처리되어야 한다."
    ]
}



scwin.onpageload = function () {
    // Global DataList 생성 호출
    $c.gcm.createCommonDatalist();

    // comp 초기 생성
    scwin.comp_init();

    // 테스트 설명, 유효성 생성
    wf_body_left.getObj("scwin").createValidation(scwin.tData);
};



// comp 생성 : 결함 수정 시 영향(blast radius)을 함께 확인하기 위한 inputCalendar 3종.
//  - target1 : 첨부(Jira)와 동일한 dateValidCheck 구성 (등록 현상 조건). 정상 붙여넣기/초과 붙여넣기/직접 타이핑/무효 붙여넣기 등 인접 경로도 함께 확인.
//  - target2 : 유효성 검증 속성 미적용 inputCalendar (등록 현상 입증용 보조).
//  - target3 : calendarValueType=yearMonthDateTime (표시 yyyy-MM-dd HH:mm) - 다른 입력형식의 붙여넣기 변환이 함께 깨지지 않는지 확인.
//  dataMap key 에 ref 바인딩. 값 변경(붙여넣기/타이핑/포커스아웃)이 일어나면 결과 표시값/getValue 를 자동으로 리턴창에 출력한다.
scwin.comp_init = async function () {
    // 기존 라벨/target/data 있으면 삭제
    if (typeof label1 !== 'undefined') {
        label1.remove();
    }
    if (typeof target1 !== 'undefined') {
        target1.remove();
    }
    if (typeof target2 !== 'undefined') {
        target2.remove();
    }
    if (typeof target3 !== 'undefined') {
        target3.remove();
    }
    if (typeof dma_date !== 'undefined') {
        $p.data.remove("dma_date");
    }

    var ns = $c.gcm.getNameSpace();

    // 안내 라벨 (target 생성 전 가장 먼저 생성) - 전제/절차/확인은 라벨로만 표기
    await $c.gcm.createLabel('label="[전제] 첫째 inputCalendar 는 dateValidCheck(유효성 검증) 관련 속성을 모두 적용한 등록 현상 조건(표시 yyyy-MM-dd, 입력 yyyyMMdd), 둘째는 유효성 검증 속성 미적용, 셋째는 calendarValueType=yearMonthDateTime(표시 yyyy-MM-dd HH:mm). 값이 변경되면 결과가 자동으로 리턴창에 출력된다.\n[등록 현상] 첫째 입력창에 (1) 유효 날짜 2026-06-24 입력 후 다른 곳 클릭 (2) 값 전체 삭제 (3) 22222222 입력 후 다른 곳 클릭하여 유효성 메시지 확인 (4) 메시지 확인 후 다시 2026-06-24 붙여넣기(Ctrl+V) -> 붙여넣은 직후 표시값이 일(日) 누락된 2026-06- 로 잘리는지 확인.\n[수정 영향 범위] 첫째에서 (가) 메시지 없는 정상 상태의 붙여넣기 (나) 표시형식 길이를 초과하는 문자열 붙여넣기 (다) 메시지 이후 직접 타이핑 (라) 무효 날짜 붙여넣기 시 유효성/메시지 발동과 부분/빈값 포커스아웃 처리를, 셋째에서 시분 포함 형식의 붙여넣기 변환을 각각 수행하여, 이 결함을 고칠 때 함께 깨질 수 있는 인접 경로가 모두 전체 값/정상 처리되는지 리턴창 표시값으로 확인."', '', 'label1');

    // ref 바인딩 대상 dataMap 생성 (BASDT: 결함조건, BASDT2: 검증속성 미적용, BASDT3: 시분 포함 형식)
    var strMap = '';
    strMap += '<w2:dataMap ' + ns + ' id="dma_date" baseNode="map">';
    strMap += '<w2:keyInfo>';
    strMap += '<w2:key id="BASDT" name="BASDT" dataType="text"></w2:key>';
    strMap += '<w2:key id="BASDT2" name="BASDT2" dataType="text"></w2:key>';
    strMap += '<w2:key id="BASDT3" name="BASDT3" dataType="text"></w2:key>';
    strMap += '</w2:keyInfo>';
    strMap += '<w2:data use="true"><BASDT></BASDT><BASDT2></BASDT2><BASDT3></BASDT3></w2:data>';
    strMap += '</w2:dataMap>';
    $p.data.create(strMap);

    var grp_comp = $c.gcm.getTestGroup();

    // target1 : 첨부와 동일한 dateValidCheck 구성 (등록 현상 조건)
    var strCal1 = '';
    strCal1 += '<w2:inputCalendar ' + ns + ' id="" ref="data:dma_date.BASDT" style="width:180px;height:23px;" calendarValueType="yearMonthDate" dateValidCheck="true" validOnInput="true" displayMessage="true" validCheck="true" validateRef="true" alt="기준일자 선택" title="기준일자 직접 입력(결함 조건)"></w2:inputCalendar>';
    scwin.target1 = await $p.dynamicCreate("target1", "inputCalendar", strCal1, grp_comp);

    // target2 : 유효성 검증 속성 미적용 inputCalendar (등록 현상 입증용 보조)
    var strCal2 = '';
    strCal2 += '<w2:inputCalendar ' + ns + ' id="" ref="data:dma_date.BASDT2" style="width:180px;height:23px;margin-left:14px;" calendarValueType="yearMonthDate" alt="기준일자 선택(검증 미적용)" title="기준일자 직접 입력(검증 미적용)"></w2:inputCalendar>';
    scwin.target2 = await $p.dynamicCreate("target2", "inputCalendar", strCal2, grp_comp);

    // target3 : 시분 포함 형식 (다른 입력형식의 붙여넣기 변환 검증)
    var strCal3 = '';
    strCal3 += '<w2:inputCalendar ' + ns + ' id="" ref="data:dma_date.BASDT3" style="width:220px;height:23px;margin-left:14px;" calendarValueType="yearMonthDateTime" dateValidCheck="true" displayMessage="true" validCheck="true" alt="기준일시 선택" title="기준일시 직접 입력(시분 포함)"></w2:inputCalendar>';
    scwin.target3 = await $p.dynamicCreate("target3", "inputCalendar", strCal3, grp_comp);

    // 값 변경 시 결과 자동 출력 핸들러 연결 (붙여넣기 시점과 입력완료 시점의 표시값/getValue 를 출력)
    scwin.wireReport(target1, "[결함조건]");
    scwin.wireReport(target2, "[검증 미적용]");
    scwin.wireReport(target3, "[시분 포함]");
}



// 표시값/getValue 출력
scwin.report = function (comp, tag) {
    var v = comp.dom.input.value;
    var gv = comp.getValue();
    wf_body_bottom.getObj("scwin").setReturnValue(tag + " / 표시값=[" + v + "], getValue()=[" + gv + "]");
};

// 값 변경 핸들러 연결 : 붙여넣기(insertFromPaste) 시점과 입력완료(change) 시점에 결과를 출력
scwin.wireReport = function (comp, tag) {
    var input = comp.dom.input;
    input.addEventListener('input', function (e) {
        // 붙여넣기 입력 시점의 표시값(엔진 처리 직후)을 출력
        if (e.inputType === 'insertFromPaste') {
            setTimeout(function () { scwin.report(comp, tag + " 붙여넣기 직후"); }, 0);
        }
    });
    input.addEventListener('change', function () {
        // 입력완료(포커스 아웃 등) 시점의 표시값을 출력
        setTimeout(function () { scwin.report(comp, tag + " 입력완료"); }, 0);
    });
};
